swift_syntax.cheat:
// Common snippets
let name: String = "Alice"
var count = 0

// Optional unwrap
guard let url = URL(string: s) else { return }

// Switch with enum
enum Result { case success(Int), failure(Error) }
switch result { case .success(let v): ... case .failure(let e): ... }

// Closure capture
someAsyncCall { [weak self] in self?.doWork() }

// Quick mapping
let doubled = [1,2,3].map { $0 * 2 }

swift_concurrency.cheat:
// Async examples
func fetchData() async throws -> Data { ... }
Task { do { let d = try await fetchData(); print(d) } catch { } }

// TaskGroup
await withTaskGroup(of: Int.self) { group in for i in 0..<4 { group.addTask { doWork(i) } } for await r in group { print(r) } }

// Actor
actor Counter { private var value = 0; func inc() { value += 1 } func get() -> Int { value } }

swift_protocols_generics.cheat:
// Protocol example
protocol Repository { associatedtype Model; func get(id: Int) -> Model? }

// Generic function
func find<T: Equatable>(_ arr: [T], _ value: T) -> Int? { arr.firstIndex(of: value) }

// Opaque return
func makeSequence() -> some Sequence { return [1,2,3] }

swift_error_handling.cheat:
// Throwing example
enum NetworkError: Error { case unreachable, timeout, unexpected(code: Int) }
func fetch() throws -> Data { throw NetworkError.unreachable }

// Calling
do { let data = try fetch() } catch { print("error: \(error)") }

// Continuation wrap
func fetchOld(_ completion:@escaping (Data?,Error?)->Void) { ... }
func fetchAsync() async throws -> Data { try await withCheckedThrowingContinuation { cont in fetchOld { d,e in if let e=e { cont.resume(throwing:e) } else { cont.resume(returning:d!) } } } }

swift_optionals_collections.cheat:
// Common patterns
let numbers = [1,2,3]
let doubled = numbers.map { $0 * 2 }
let maybe: [Int?] = [1, nil, 3]
let compact = maybe.compactMap { $0 }

// Lazy chain
let seq = (0..<1_000_000).lazy.map { $0 * 2 }.filter { $0 % 3 == 0 }.prefix(100)

